INSERT INTO bulletins (id, user_id, category, title, body, link, event_date, pinned, likes_count, comments_count, created_at) VALUES
  ('d0000000-0000-0000-0000-000000000001', 'a0000000-0000-0000-0000-000000000001', 'hackathon', 'Smart India Hackathon 2025 — Registrations Open', 'Form teams of 6 and register before Feb 28. Problem statements released on the portal.', 'https://sih.gov.in', '2025-02-28', true, 142, 18, '2025-02-01T10:00:00Z'),
