  ('d0000000-0000-0000-0000-000000000003', 'a0000000-0000-0000-0000-000000000002', 'club', 'Coding Club — Weekly DSA Contest', 'Every Saturday 8pm on Codeforces. Join the team board for the ladder.', NULL, NULL, false, 64, 8, '2025-02-08T10:00:00Z'),
  ('d0000000-0000-0000-0000-000000000004', 'a0000000-0000-0000-0000-000000000006', 'exam', 'End-Sem Exam Schedule Released', 'Datesheet for sem 5 and 6 is out. Check the student portal. Exams start March 10.', NULL, '2025-03-10', false, 87, 22, '2025-02-10T10:00:00Z'),
  ('d0000000-0000-0000-0000-000000000005', 'a0000000-0000-0000-0000-000000000003', 'lostfound', 'Lost: Black wallet near Library', 'Found a black leather wallet near the central library on Tuesday. DM me to claim.', NULL, NULL, false, 21, 4, '2025-02-12T10:00:00Z'),
